import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"32. Accident Make Up Pay","description":"","frontmatter":{"title":"32. Accident Make Up Pay","eba":"Biomedical Engineers 2025-2028","topics":["hours","wages","accident-pay","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/32-accident-make-up-pay.md","filePath":"ebas/biomedical-engineers/wages/32-accident-make-up-pay.md"}'),i={name:"ebas/biomedical-engineers/wages/32-accident-make-up-pay.md"};function r(p,e,s,c,m,l){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_32-accident-make-up-pay" tabindex="-1">32. Accident Make Up Pay <a class="header-anchor" href="#_32-accident-make-up-pay" aria-label="Permalink to &quot;32. Accident Make Up Pay&quot;">​</a></h1><p><strong>32.1</strong> Entitlement to accident make-up pay An Employee receiving compensation for incapacity under the WIRC Act will be entitled to accident make-up pay from the Employer who is liable to pay compensation in accordance with this clause (including pro-rata for any part of a week).</p><p><strong>32.2</strong> Definitions</p><p><strong>(a)</strong> Accident make-up pay means:</p><p><strong>(i)</strong> In the case of an Employee with no current work capacity, a payment equal to the ordinary time earnings the Employee would ordinarily receive had the Employee been performing their normal duties and hours of work, less the amount of weekly compensation.</p><p><strong>(ii)</strong> In the case of an Employee with a current work capacity, a payment equal to the ordinary time earnings the Employee would ordinarily receive, had the Employee been performing their normal duties and hours of work less the amount of weekly compensation and less the average amount the Employee is earning in suitable employment.</p><p><strong>(b)</strong> Injury under this clause has the same meaning as workers’ compensation legislation and includes a disease contracted by an Employee in the course of the Employee’s employment.</p><p><strong>(c)</strong> Ordinary time earnings excludes additional remuneration by way of shift premiums, overtime payments, special rates or other similar payments.</p><p><strong>(d)</strong> Suitable Employment for the purposes of this clause 32 has the same meaning as the definition in the WIRC Act.</p><p><strong>32.3</strong> Maximum payment The maximum period or aggregate of periods of accident make-up pay to be made by an Employer will be a total of 39 weeks for any one injury.</p><p><strong>32.4</strong> Accident Make-Up Pay will not apply in some circumstances Accident make-up pay in accordance with this clause will not apply:</p><p><strong>(a)</strong> in respect of any injury during the first five normal working days of incapacity, except where the Employee contracts an infectious disease for which the Employee is entitled to receive workers compensation in which case accident make-up pay will apply from the first day of the incapacity;</p><p><strong>(b)</strong> to any incapacity occurring during the first two weeks of employment unless that incapacity continues beyond the first two weeks in which case accident make-up pay will apply only to the period of incapacity after the first two weeks;</p><p><strong>(c)</strong> during any period when the Employee fails to comply with the requirements of the WIRC Act with regard to examination by a medical practitioner;</p><p><strong>(d)</strong> where the injury for which the Employee is receiving weekly compensation payments is a pre-existing injury that work has contributed to by way of recurrence, aggravation, acceleration, exacerbation or deterioration, and the Employee failed to disclose the injury on engagement:</p><p><strong>(i)</strong> following a request to do so by the Employer; and</p><p><strong>(ii)</strong> the Employer providing the Employee details of the requirements of the position; and</p><p><strong>(iii)</strong> where the Employee knew, or ought to have known, that the nature of the injury, may impact on the ability of the Employee to undertake the work;</p><p><strong>(e)</strong> where the injury subject to recurrence, aggravation or acceleration as provided under workers’ compensation legislation or industrial diseases contracted by a gradual process, unless the Employee has been employed with the Employer at the time of the incapacity for a minimum period of one month;</p><p><strong>(f)</strong> where in accordance with the WIRC Act a medical practitioner provides information to an Employer of an Employee’s fitness for work or specifies work for which an</p><p>Employee has a capacity and that work is made available by an Employer but not commenced by an Employee;</p><p><strong>(g)</strong> when the claim has been ceased or redeemed in accordance with the WIRC Act;</p><p><strong>(h)</strong> in respect of any paid leave of absence.</p><p><strong>32.5</strong> Reduction of compensation Where an Employee receives a weekly payment under this clause and subsequently that payment is reduced pursuant to the WIRC Act, that reduction will not render the Employer liable to increase the amount of accident pay in respect of that injury.</p><p><strong>32.6</strong> Termination of employment</p><p><strong>(a)</strong> Termination of Employment by the Employee Accident make-up pay ceases where the Employee terminates their employment except:</p><p><strong>(i)</strong> if an Employee with partial incapacity cannot obtain suitable employment from the Employer but such alternative employment is available with another Employer; and</p><p><strong>(ii)</strong> the Employee, if required, provides evidence to the Employer of the continuing payment of weekly compensation payments.</p><p><strong>(b)</strong> Termination of Employment by the Employer An entitlement to accident make-up pay does not cease on termination where the Employer terminates the Employee’s employment, except where the termination is for serious and wilful misconduct.</p><p><strong>32.7</strong> Civil damage claims</p><p><strong>(a)</strong> An Employee receiving or who received accident make-up pay must advise the Employer of any action or claim the Employee may institute for damages. If requested, the Employee will provide an authority to the Employer entitling the Employer to a charge upon any money payable pursuant to any judgment or settlement on that injury.</p><p><strong>(b)</strong> Where an Employee obtains a judgment or settlement for damages in respect of an injury for which the Employee received accident make-up pay, the Employer’s liability to pay accident make-up pay ceases from the date of such judgment or settlement where the damages are not reduced (in whole or part) by the accident make-up pay paid by the Employer. Where damages from a judgment or settlement are not reduced to take into account accident make-up pay paid by the Employer (in whole or part), the Employee must repay the Employer the accident make-up pay to the extent the damages were not reduced.</p><p><strong>(c)</strong> Where an Employee obtains a judgment or settlement for damages against a person other than the Employer in respect of an injury for which the Employee received accident make-up pay, the Employer’s liability to pay accident make-up pay will cease from the date of such judgment or settlement where the damages are not reduced (in whole or part) by the amount of accident pay made by the Employer. The Employee must pay to her/his Employer any amount of accident pay already received in respect of that injury by which the judgment or settlement has not been so reduced.</p><p>REIMBURSEMENTS</p>',34)])])}const d=t(i,[["render",r]]);export{h as __pageData,d as default};
